#include<bits/stdc++.h>
using namespace std;
struct node
{
    int l,r,f;
    bool operator<(const node&b)const
    {
        if(r==b.r)
        {
            return l<b.l;
        }
        return r<b.r;
    }
};
set<node> st;
char str[1200010];
int a[200010];
char op[200010];
const long long mod=1e9+7;
long long s[200010],invs[200010];
long long getsum(long long l,long long r)
{
    return s[r]*invs[l-1]%mod;
}
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
long long calc(node x)
{
    return ((x.f*getsum(x.l,x.r)%mod)%mod+mod)%mod;
}
int main()
{
    scanf("%s",str+1);
    int n=strlen(str+1);
    node now;
    int m=0,k=0;
    for(int i=1;i<=n;i++)
    {
        if(isdigit(str[i]))
        {
            int j=i,val=0;
            do
            {
                val=val*10+(str[j]-'0');
                j++;
            }
            while(isdigit(str[j]));
            i=j-1;
            a[++m]=val;
        }
        else
        {
            op[++k]=str[i];
        }
    }
    s[0]=invs[0]=1;
    for(int i=1;i<=m;i++)
    {
        s[i]=s[i-1]*a[i]%mod;
        invs[i]=fastpow(s[i],mod-2);
    }
    long long ans=0;
    int nowl=1,f=1;
    for(int i=2;i<=m;i++)
    {
        if(op[i-1]!='*')
        {
            st.insert((node){nowl,i-1,f});
            nowl=i;
            if(op[i-1]=='+')
            {
                f=1;
            }
            else
            {
                f=-1;
            }
        }
    }
    if(nowl<=m)
    {
        st.insert((node){nowl,m,f});
    }
    for(auto i:st)
    {
        ans+=calc(i);
        ans%=mod;
    }
    printf("%lld\n",ans);
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int x;
        char ch;
        scanf("%d",&x);
        cin>>ch;
        if(op[x]!='*'||ch=='*')
        {
            continue;
        }
        op[x]=ch;
        x++;
        auto it=st.lower_bound((node){0,x,0});
        if(it==st.end())
        {
            cerr<<"Error\n";
        }
        node t=(*it);
        st.erase(it);
        ans-=calc(t);
        node nxt1,nxt2;
        nxt1.l=t.l;
        nxt2.r=t.r;
        nxt1.f=t.f;
        nxt2.f=(ch=='+'?1:-1);
        nxt1.r=x-1;
        nxt2.l=x;
        st.insert(nxt1);
        st.insert(nxt2);
        ans+=calc(nxt1)+calc(nxt2);
        ans=(ans%mod+mod)%mod;
        printf("%lld\n",ans);
    }
    return 0;
}
